// Build the Gemini API multimodal request payload.
// The two reference images are read from the form's binary uploads
// and are NOT modified or warped in any way.

const item = $input.first();

// Get the prompt from the form submission
const prompt = item.json['Image Prompt'];
if (!prompt) {
  throw new Error('Missing required field: Image Prompt');
}

// Get file binary data from the form uploads
const binaryKeys = Object.keys(item.binary || {});
if (binaryKeys.length < 2) {
  throw new Error('Two image files are required. Only ' + binaryKeys.length + ' file(s) were uploaded.');
}

// --- FIX STARTS HERE ---
// Read the two uploaded images using getBinaryDataBuffer to resolve filesystem pointers
const key1 = binaryKeys[0];
const key2 = binaryKeys[1];

// Helper to convert binary to base64
async function getBase64(index, key) {
  const buffer = await this.helpers.getBinaryDataBuffer(index, key);
  return buffer.toString('base64');
}

// Convert both images to base64
const image1Base64 = await getBase64.call(this, 0, key1);
const image2Base64 = await getBase64.call(this, 0, key2);
// --- FIX ENDS HERE ---

const file1 = item.binary[key1];
const file2 = item.binary[key2];
const mimeType1 = file1.mimeType || 'image/png';
const mimeType2 = file2.mimeType || 'image/png';

const payload = {
  contents: [
    {
      role: "user",
      parts: [
        {
          inlineData: {
            mimeType: mimeType1,
            data: image1Base64
          }
        },
        {
          inlineData: {
            mimeType: mimeType2,
            data: image2Base64
          }
        },
        {
          text: prompt + "\n\nIMPORTANT: Use the two provided images as exact references. Do NOT warp, distort, or modify those images in any way. Generate a new image that incorporates them faithfully."
        }
      ]
    }
  ],
  generationConfig: {
    responseModalities: ["TEXT", "IMAGE"],
    temperature: 1,
    topP: 0.95,
    topK: 40
  }
};

return [{ json: { payload } }];

// Extract the generated image and any text from the Gemini API response.

const response = $input.first().json;

// Handle error responses
if (response.error) {
  return [{
    json: {
      success: false,
      error: response.error.message || 'Unknown API error',
      code: response.error.code || 500
    }
  }];
}

const candidates = response.body?.candidates || response.candidates;
if (!candidates || candidates.length === 0) {
  return [{
    json: {
      success: false,
      error: 'No candidates returned by the model. The request may have been blocked by safety filters.'
    }
  }];
}

const parts = candidates[0].content?.parts || [];

let generatedImageBase64 = null;
let generatedMimeType = null;
let textResponse = '';

for (const part of parts) {
  if (part.inlineData) {
    generatedImageBase64 = part.inlineData.data;
    generatedMimeType = part.inlineData.mimeType;
  }
  if (part.text) {
    textResponse += part.text;
  }
}

if (!generatedImageBase64) {
  return [{
    json: {
      success: false,
      error: 'No image was generated. The model returned only text.',
      textResponse: textResponse
    }
  }];
}

return [{
  json: {
    success: true,
    generatedImage: generatedImageBase64,
    mimeType: generatedMimeType,
    dataUri: `data:${generatedMimeType};base64,${generatedImageBase64}`,
    textResponse: textResponse
  }
}];
